import { writeFile, mkdir } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import path from "node:path";

const here = path.dirname(fileURLToPath(import.meta.url));
// Fixtures now live under src/generated/ (relocated from src/). The step-1
// generated file at src/fixtures.gen.mjs no longer satisfies the suite, so the
// generator must be run again for this step.
const OUT = path.resolve(here, "..", "src", "generated", "fixtures.gen.mjs");

const CASES = [
  ["Hello World", "hello-world"],
  ["fooBarBaz", "foo-bar-baz"],
  ["  spaced  out  ", "spaced-out"],
  ["already-kebab", "already-kebab"],
  ["Mixed_Snake case", "mixed-snake-case"],
];

const banner = "// GENERATED by `npm run gen` (scripts/gen.mjs). Do not edit or commit.\n";
await mkdir(path.dirname(OUT), { recursive: true });
await writeFile(OUT, banner + `export const KEBAB_CASES = ${JSON.stringify(CASES, null, 2)};\n`);
console.log(`gen: wrote ${path.relative(process.cwd(), OUT)} (${CASES.length} cases)`);
